Here's a complete implementation:

### XAML — `ItemsPage.xaml`

```xml
<ContentPage xmlns="http://schemas.microsoft.com/dotnet/2021/maui"
             xmlns:x="http://schemas.microsoft.com/winfx/2009/xaml"
             xmlns:vm="clr-namespace:MyApp.ViewModels"
             xmlns:models="clr-namespace:MyApp.Models"
             x:Class="MyApp.Views.ItemsPage"
             x:DataType="vm:ItemsViewModel">

    <RefreshView IsRefreshing="{Binding IsRefreshing}"
                 Command="{Binding RefreshCommand}">

        <CollectionView ItemsSource="{Binding Items}"
                        SelectionMode="Single"
                        SelectedItem="{Binding CurrentItem, Mode=TwoWay}"
                        SelectionChangedCommand="{Binding ItemSelectedCommand}">

            <CollectionView.ItemsLayout>
                <LinearItemsLayout Orientation="Vertical"
                                   ItemSizingStrategy="MeasureFirstItem" />
            </CollectionView.ItemsLayout>

            <CollectionView.ItemTemplate>
                <DataTemplate x:DataType="models:Item">
                    <Grid Padding="12" ColumnDefinitions="48,*">
                        <Image Source="{Binding Icon}"
                               WidthRequest="40" HeightRequest="40" />
                        <VerticalStackLayout Grid.Column="1" VerticalOptions="Center">
                            <Label Text="{Binding Name}" FontAttributes="Bold" />
                            <Label Text="{Binding Description}"
                                   FontSize="12" TextColor="Gray" />
                        </VerticalStackLayout>
                    </Grid>
                </DataTemplate>
            </CollectionView.ItemTemplate>

            <CollectionView.EmptyView>
                <ContentView>
                    <Label Text="No items found."
                           HorizontalOptions="Center"
                           VerticalOptions="Center" />
                </ContentView>
            </CollectionView.EmptyView>

        </CollectionView>
    </RefreshView>
</ContentPage>
```

### ViewModel — `ItemsViewModel.cs`

```csharp
using CommunityToolkit.Mvvm.ComponentModel;
using CommunityToolkit.Mvvm.Input;
using System.Collections.ObjectModel;

namespace MyApp.ViewModels;

public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;

    public ItemsViewModel(IApiService api)
    {
        _api = api;
    }

    public ObservableCollection<Item> Items { get; } = new();

    [ObservableProperty]
    private Item? _currentItem;

    [ObservableProperty]
    private bool _isRefreshing;

    [RelayCommand]
    private async Task ItemSelectedAsync()
    {
        if (CurrentItem is null) return;

        await Shell.Current.GoToAsync(
            $"{nameof(DetailPage)}?id={CurrentItem.Id}");

        // Clear selection so the same item can be re-selected later
        CurrentItem = null;
    }

    [RelayCommand]
    private async Task RefreshAsync()
    {
        try
        {
            var freshData = await _api.GetItemsAsync();

            // Update on UI thread
            MainThread.BeginInvokeOnMainThread(() =>
            {
                Items.Clear();
                foreach (var item in freshData)
                    Items.Add(item);
            });
        }
        finally
        {
            IsRefreshing = false;   // Stops the spinner
        }
    }
}
```

### Key binding relationships

| XAML Property | ViewModel Property | Purpose |
|---|---|---|
| `RefreshView.IsRefreshing` | `IsRefreshing` (bool) | Shows/hides spinner; **set to `false` when done** |
| `RefreshView.Command` | `RefreshCommand` | Fires on pull-down gesture |
| `CollectionView.ItemsSource` | `Items` (`ObservableCollection<T>`) | Data source — must be observable |
| `CollectionView.SelectedItem` | `CurrentItem` (`TwoWay`) | Tracks the selected object |
| `SelectionChangedCommand` | `ItemSelectedCommand` | Fires when selection changes → triggers navigation |

### Important notes

- **`ObservableCollection<T>`** — never use `List<T>`; the UI won't update on add/remove.
- **`MeasureFirstItem`** — improves scroll performance when items are uniform height.
- **Reset `CurrentItem = null`** after navigation so the same item can be tapped again.
- **Set `IsRefreshing = false`** in `finally` to always dismiss the refresh spinner.
- **`x:DataType`** on both the page and the `DataTemplate` enables compiled bindings (catches errors at build time).
